{
  "lessons": [
    {
      "description": "Recognize and use the Spanish subject pronouns like yo, tú, usted, él, ella, nosotros, and ustedes, and choose the right one for the person you are talking about.",
      "kind": "grammar",
      "title": "Subject Pronouns"
    },
    {
      "description": "Build present-tense forms of regular -ar verbs like hablar, trabajar, and estudiar by swapping the ending for -o, -as, -a, -amos, and -an.",
      "kind": "grammar",
      "title": "Regular -ar Verb Conjugation"
    },
    {
      "description": "Conjugate regular -er and -ir verbs like comer, beber, vivir, and escribir in the present tense, and compare the endings the two groups share and where they differ.",
      "kind": "grammar",
      "title": "Regular -er and -ir Verb Conjugation"
    },
    {
      "description": "Use the irregular verb ser (soy, eres, es, somos, son) to talk about identity, origin, profession, and permanent traits.",
      "kind": "grammar",
      "title": "The Verb Ser"
    },
    {
      "description": "Use the irregular verb estar (estoy, estás, está, estamos, están) to talk about location, feelings, and temporary conditions.",
      "kind": "grammar",
      "title": "The Verb Estar"
    },
    {
      "description": "Choose between ser and estar in real sentences, distinguishing pairs like es aburrido vs. está aburrido and where something is vs. what something is.",
      "kind": "grammar",
      "title": "Ser vs. Estar"
    },
    {
      "description": "Conjugate tener (tengo, tienes, tiene, tenemos, tienen) and use everyday expressions like tener hambre, tener sed, tener frío, and tener años.",
      "kind": "grammar",
      "title": "Tener and Tener Expressions"
    },
    {
      "description": "Conjugate ir (voy, vas, va, vamos, van) to say where people are going, and use ir a + infinitive to talk about what someone is going to do.",
      "kind": "grammar",
      "title": "Ir and Ir a + Infinitive"
    },
    {
      "description": "Recognize and use everyday routine verbs like trabajar, estudiar, cocinar, caminar, escuchar, and mirar to describe what people do each day.",
      "kind": "vocabulary",
      "title": "Daily Routine Verbs"
    },
    {
      "description": "Recognize and use common -er and -ir action verbs like comer, beber, leer, aprender, vivir, escribir, and abrir in short everyday sentences.",
      "kind": "vocabulary",
      "title": "Everyday -er and -ir Action Verbs"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Reconheça e use cumprimentos comuns como hello, hi, good morning, good afternoon e good evening, escolhendo o adequado para cada momento do dia.",
      "kind": "vocabulary",
      "title": "Cumprimentos ao Longo do Dia"
    },
    {
      "description": "Use despedidas como goodbye, bye, see you later, good night e take care em situações formais e informais.",
      "kind": "vocabulary",
      "title": "Despedidas"
    },
    {
      "description": "Apresente-se com frases como I'm..., My name is... e responda apresentações com Nice to meet you.",
      "kind": "vocabulary",
      "title": "Frases de Apresentação"
    },
    {
      "description": "Pergunte e responda sobre nomes com What's your name? e sobre origem com Where are you from? e I'm from Brazil.",
      "kind": "vocabulary",
      "title": "Perguntas sobre Nome e Origem"
    },
    {
      "description": "Use expressões de cortesia como please, thank you, you're welcome, excuse me e sorry nas situações certas.",
      "kind": "vocabulary",
      "title": "Expressões de Cortesia"
    },
    {
      "description": "Pergunte e responda How are you? com variações como I'm fine, pretty good e not bad, mantendo uma pequena conversa inicial.",
      "kind": "vocabulary",
      "title": "Como Vai Você?"
    },
    {
      "description": "Construa frases com o verbo to be no presente (I am, you are, he is) e suas contrações (I'm, you're, he's) para se apresentar e falar de origem.",
      "kind": "grammar",
      "title": "Verbo To Be: Afirmativas e Contrações"
    },
    {
      "description": "Forme perguntas com o verbo to be (Are you...?, Is she...?) e com palavras interrogativas como what e where para pedir informações pessoais.",
      "kind": "grammar",
      "title": "Perguntas com To Be e Palavras Interrogativas"
    },
    {
      "description": "Escolha os pronomes pessoais corretos (I, you, he, she, we, they) e os possessivos my, your, his e her ao falar de nomes e apresentações.",
      "kind": "grammar",
      "title": "Pronomes Pessoais e Possessivos"
    },
    {
      "description": "Distinga registros formais e informais em cumprimentos e apresentações, como Hi versus Good morning e How's it going? versus How do you do?.",
      "kind": "grammar",
      "title": "Formal e Informal em Saudações"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Reconheça e leia as cinco vogais do hiragana: あ, い, う, え, お, a base de todo o silabário.",
      "kind": "alphabet",
      "title": "Vogais あ・い・う・え・お"
    },
    {
      "description": "Reconheça e leia os caracteres da linha K: か, き, く, け, こ, e associe cada um ao seu som.",
      "kind": "alphabet",
      "title": "Linha K: か・き・く・け・こ"
    },
    {
      "description": "Reconheça e leia os caracteres da linha S: さ, し, す, せ, そ, incluindo a leitura irregular de し (shi).",
      "kind": "alphabet",
      "title": "Linha S: さ・し・す・せ・そ"
    },
    {
      "description": "Reconheça e leia os caracteres da linha T: た, ち, つ, て, と, incluindo as leituras irregulares de ち (chi) e つ (tsu).",
      "kind": "alphabet",
      "title": "Linha T: た・ち・つ・て・と"
    },
    {
      "description": "Reconheça e leia os caracteres da linha N: な, に, ぬ, ね, の, distinguindo formas parecidas como ぬ e ね.",
      "kind": "alphabet",
      "title": "Linha N: な・に・ぬ・ね・の"
    },
    {
      "description": "Reconheça e leia os caracteres da linha H: は, ひ, ふ, へ, ほ, incluindo o som de ふ (fu).",
      "kind": "alphabet",
      "title": "Linha H: は・ひ・ふ・へ・ほ"
    },
    {
      "description": "Reconheça e leia os caracteres da linha M: ま, み, む, め, も, diferenciando め de ぬ e も de ほ.",
      "kind": "alphabet",
      "title": "Linha M: ま・み・む・め・も"
    },
    {
      "description": "Reconheça e leia os caracteres da linha Y (や, ゆ, よ) e da linha R (ら, り, る, れ, ろ).",
      "kind": "alphabet",
      "title": "Linhas Y e R: や・ゆ・よ e ら・り・る・れ・ろ"
    },
    {
      "description": "Reconheça e leia わ, を e a consoante final ん, entendendo o uso de を como partícula e de ん no fim de sílabas.",
      "kind": "alphabet",
      "title": "わ・を e a consoante ん"
    },
    {
      "description": "Reconheça os sons sonorizados com dakuten (゛): が, ざ, だ e ば, comparando cada um com sua forma original.",
      "kind": "alphabet",
      "title": "Dakuten: linhas が・ざ・だ・ば"
    },
    {
      "description": "Reconheça a linha ぱ・ぴ・ぷ・ぺ・ぽ com handakuten (゜) e distinga os sons H, B e P entre は, ば e ぱ.",
      "kind": "alphabet",
      "title": "Handakuten: linha ぱ・ぴ・ぷ・ぺ・ぽ"
    },
    {
      "description": "Reconheça e leia combinações yōon com や, ゆ e よ pequenos, como きゃ, しゅ e ちょ, diferenciando-as das sílabas separadas.",
      "kind": "alphabet",
      "title": "Combinações yōon: きゃ・しゅ・ちょ e similares"
    },
    {
      "description": "Leia e escreva palavras japonesas simples usando apenas hiragana, como ねこ, すし, みず e ありがとう, praticando o reconhecimento em contexto.",
      "kind": "vocabulary",
      "title": "Primeiras palavras em hiragana"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Recognize and read the six basic vowels ㅏ, ㅓ, ㅗ, ㅜ, ㅡ, and ㅣ, matching each shape to its sound.",
      "kind": "alphabet",
      "title": "Basic Vowels ㅏ ㅓ ㅗ ㅜ ㅡ ㅣ"
    },
    {
      "description": "Recognize the y-vowels ㅑ, ㅕ, ㅛ, and ㅠ and see how the extra stroke adds a 'y' sound to the base vowel.",
      "kind": "alphabet",
      "title": "Y-Vowels ㅑ ㅕ ㅛ ㅠ"
    },
    {
      "description": "Recognize and read the consonants ㄱ, ㄴ, ㄷ, ㄹ, and ㅁ, connecting each letter shape to its sound.",
      "kind": "alphabet",
      "title": "Consonants ㄱ ㄴ ㄷ ㄹ ㅁ"
    },
    {
      "description": "Recognize and read the consonants ㅂ, ㅅ, ㅇ, ㅈ, and ㅎ, including ㅇ as a silent placeholder at the start of a syllable.",
      "kind": "alphabet",
      "title": "Consonants ㅂ ㅅ ㅇ ㅈ ㅎ"
    },
    {
      "description": "Recognize the aspirated consonants ㅋ, ㅌ, ㅍ, and ㅊ and match each to its plain counterpart ㄱ, ㄷ, ㅂ, and ㅈ.",
      "kind": "alphabet",
      "title": "Aspirated Consonants ㅋ ㅌ ㅍ ㅊ"
    },
    {
      "description": "Build consonant-plus-vowel syllable blocks, placing the vowel to the right of or below the consonant, as in 가, 노, 무, and 시.",
      "kind": "alphabet",
      "title": "Building Syllable Blocks: Consonant + Vowel"
    },
    {
      "description": "Read syllables with a final consonant (batchim) at the bottom of the block, such as 강, 밥, 문, and 을, and hear how ㅇ sounds as 'ng' in final position.",
      "kind": "alphabet",
      "title": "Final Consonants: Batchim Position"
    },
    {
      "description": "Distinguish easily confused letter pairs like ㅏ/ㅓ, ㅗ/ㅜ, ㄱ/ㅋ, ㄷ/ㅌ, and ㅂ/ㅍ by spotting the stroke differences that change the sound.",
      "kind": "alphabet",
      "title": "Look-Alike Letters: Common Visual Contrasts"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Construye oraciones hipotéticas con la estructura \"If + pasado simple, would + verbo base\", como \"If I had more time, I would travel more\".",
      "kind": "grammar",
      "title": "Second Conditional: If + Past Simple, Would"
    },
    {
      "description": "Usa \"were\" con todos los sujetos en situaciones hipotéticas y aplica la expresión \"If I were you\" para dar consejos.",
      "kind": "grammar",
      "title": "Hypothetical \"Were\" and \"If I Were You\""
    },
    {
      "description": "Forma afirmaciones, negaciones y preguntas con \"would\", incluyendo contracciones como \"I'd\" y \"wouldn't\", y respuestas cortas.",
      "kind": "grammar",
      "title": "Would: Affirmative, Negative, and Questions"
    },
    {
      "description": "Distingue entre \"would\", \"could\" y \"might\" en la cláusula de resultado para expresar certeza, posibilidad o habilidad hipotética.",
      "kind": "grammar",
      "title": "Could and Might in Result Clauses"
    },
    {
      "description": "Compara la primera y la segunda condicional para elegir entre situaciones reales y probables frente a situaciones imaginarias o poco probables.",
      "kind": "grammar",
      "title": "First vs. Second Conditional"
    },
    {
      "description": "Ordena las cláusulas de la condicional en ambas posiciones y aplica la coma correctamente, como en \"I would move abroad if I could\".",
      "kind": "grammar",
      "title": "Clause Order and Punctuation in Conditionals"
    },
    {
      "description": "Reconoce y usa expresiones para plantear hipótesis como \"what if\", \"imagine\", \"suppose\", \"in your shoes\" y \"in that case\".",
      "kind": "vocabulary",
      "title": "Expressions for Imagining and Supposing"
    },
    {
      "description": "Usa frases comunes de escenarios hipotéticos como \"win the lottery\", \"quit your job\", \"move abroad\", \"be famous\" y \"have superpowers\" para conversar sobre situaciones imaginarias.",
      "kind": "vocabulary",
      "title": "Common Hypothetical Scenarios"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Reconheça e use adjetivos e verbos comuns para descrever aparência e estados, como parecer cansado, feliz, caro, delicioso ou prestes a chover.",
      "kind": "vocabulary",
      "title": "Palavras para descrever aparência e estados"
    },
    {
      "description": "Construa frases com 〜そうだ para dizer que algo parece de certo jeito, com as conjugações de adjetivos e verbos e as formas irregulares よさそう e なさそう.",
      "kind": "grammar",
      "title": "〜そうだ de aparência"
    },
    {
      "description": "Use 〜そうだ com a forma plana para relatar boatos e informações ouvidas, e distinga essa estrutura do そうだ de aparência.",
      "kind": "grammar",
      "title": "〜そうだ de boato"
    },
    {
      "description": "Reconheça e use fontes de informação e expressões de suposição como 〜によると, うわさ, 天気予報, どうやら e たぶん em frases de inferência.",
      "kind": "vocabulary",
      "title": "Fontes de informação e expressões de suposição"
    },
    {
      "description": "Faça inferências com 〜らしい a partir de informações externas e use らしい também no sentido de típico, como 男らしい ou 春らしい.",
      "kind": "grammar",
      "title": "〜らしい: inferência e tipicidade"
    },
    {
      "description": "Construa comparações e suposições com 〜みたい e sua forma mais formal 〜ようだ, ligando-as a substantivos, adjetivos e verbos.",
      "kind": "grammar",
      "title": "〜みたい e 〜ようだ"
    },
    {
      "description": "Compare 〜そうだ, 〜らしい, 〜みたい e 〜ようだ e escolha a forma certa conforme a evidência disponível e o registro formal ou informal da conversa.",
      "kind": "grammar",
      "title": "Escolhendo entre そう, らしい e みたい"
    }
  ]
}

{
  "lessons": [
    {
      "description": "Distinguish core perception and knowledge pairs like savoir vs. connaître, voir vs. regarder, and entendre vs. écouter, choosing the right verb based on intention and awareness.",
      "kind": "grammar",
      "title": "Savoir vs. Connaître and Perception Verb Pairs"
    },
    {
      "description": "Compare speech verbs such as dire, parler, raconter, exprimer, and évoquer, and pick the one that matches what is communicated and how.",
      "kind": "vocabulary",
      "title": "Verbs of Saying: Dire, Parler, Raconter, Évoquer"
    },
    {
      "description": "Recognize the three main registers of French — soutenu, courant, and familier — and match synonym sets like voiture/bagnole, manger/bouffer, and travail/boulot to the right social context.",
      "kind": "grammar",
      "title": "Register Levels: Soutenu, Courant, Familier"
    },
    {
      "description": "Choose between near-synonymous adjectives with different connotations, such as célèbre vs. notoire, économe vs. avare, and curieux vs. indiscret, based on positive or negative shading.",
      "kind": "vocabulary",
      "title": "Connotation in Adjectives: Praise or Criticism"
    },
    {
      "description": "Distinguish verbs of change and causation like changer, modifier, transformer, bouleverser, and altérer, ranking them by intensity and formality.",
      "kind": "vocabulary",
      "title": "Shades of Change: Modifier, Transformer, Bouleverser"
    },
    {
      "description": "Compare emotion vocabulary along intensity scales, such as content/heureux/ravi/comblé and triste/abattu/effondré, and select the word that matches the strength of feeling.",
      "kind": "vocabulary",
      "title": "Emotion Intensity Scales"
    },
    {
      "description": "Use elegant intensifiers and downtoners like fort, bien, tout à fait, quelque peu, and plutôt, and see how adverb choice shifts tone from neutral to formal or ironic.",
      "kind": "grammar",
      "title": "Intensifiers and Hedging Adverbs"
    },
    {
      "description": "Distinguish near-synonyms for asking and requesting — demander, solliciter, exiger, réclamer, quémander — according to politeness, insistence, and register.",
      "kind": "vocabulary",
      "title": "Requesting and Demanding: Demander to Exiger"
    },
    {
      "description": "Recognize how word order and structure change meaning with adjectives like ancien, propre, seul, and pauvre, where placement before or after the noun shifts the sense.",
      "kind": "grammar",
      "title": "Adjective Placement and Meaning Shifts"
    },
    {
      "description": "Compare verbs of thinking and believing such as penser, croire, estimer, considérer, and juger, and choose the one that signals the right degree of certainty and formality.",
      "kind": "vocabulary",
      "title": "Opinion Verbs: Penser, Croire, Estimer, Juger"
    },
    {
      "description": "Distinguish euphemisms and softened expressions like décéder vs. mourir, non-voyant vs. aveugle, and licencier vs. virer, matching each to formal, neutral, or blunt contexts.",
      "kind": "vocabulary",
      "title": "Euphemism and Directness"
    },
    {
      "description": "Build precise negative and restrictive nuance with ne...guère, ne...point, ne...que, and sans que, and compare their tone with everyday negation.",
      "kind": "grammar",
      "title": "Nuanced Negation: Guère, Point, Ne...Que"
    }
  ]
}
